const accordeon=document.querySelectorAll(".accordeon-section"),burgerMenu=document.querySelector(".menu-btn"),wrapper=document.querySelector(".wrapper-burger-menu"),menuBox=document.querySelector(".menu-burger-section"),headerMenu=document.querySelectorAll(".header-nav-list");headerMenu.forEach((function(e){e.addEventListener("click",(function(e){document.querySelectorAll(".inner-nav-items").forEach((function(e){e.classList.remove("active-block")})),e.target.closest("li").querySelector(".inner-nav-items").classList.toggle("active-block")}))})),burgerMenu.addEventListener("click",(function(){menuBox.classList.toggle("active-block"),wrapper.classList.toggle("active-wrapper"),document.body.style.overflow="hidden"}));const accordeonClick=function(e){accordeon.forEach((function(e){e.querySelector(".accordeon-panel").style.maxHeight="0px"}));let c=e.target.closest(".accordeon-section").querySelector(".accordeon-panel").scrollHeight;e.target.closest(".accordeon-section").querySelector(".accordeon-panel").style.maxHeight=c+"px",menuBox.style.minHeight=790+c+"px"};accordeon.forEach((function(e){e.addEventListener("click",accordeonClick)}));